 &lt;h1 id=&#34;入群二维码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#入群二维码&#34;&gt;#&lt;/a&gt; &lt;strong&gt;&lt;span class=&#34;red&#34;&gt;入&lt;/span&gt;&lt;span class=&#34;yellow&#34;&gt;群&lt;/span&gt;&lt;span class=&#34;green&#34;&gt;二&lt;/span&gt;&lt;span class=&#34;aqua&#34;&gt;维&lt;/span&gt;&lt;span class=&#34;blue&#34;&gt;码&lt;/span&gt;&lt;/strong&gt;&lt;/h1&gt;
